INSERT INTO `sys_log` VALUES (42018, 'admin', 'GET', 'com.example.authority.controller.NoticeController.findAll()', '[]', '2025-07-12 11:24:06', '127.0.0.1', 'Result(code=200, msg=操作成功, data=[Notice(id=17, name=v2026.0.3, content=drawer 宽度属性应该设置为 size ； 后台首页头像压扁问题 ； xss 攻击过滤器 ； dos 攻击过滤器 ； sql 注入过滤器 ； 防抖处理器且加入白名单（前后端）； 模板文件需要加路由对象 ； 动画侦听 需要后续加强处理 ； 分页查询处 bug； router 和 route 的合理设置 ； satoken 白名单 ； 页面通用类没有添加 操作中 ； 新增和编辑的响应式 warning 问题 ； 删除掉没用的静态资源对 ； 网络错误处理 （已经增强，后续需要观察）； 删除掉无用的文件 ； 登录确认登录后验证码无法出现的问题 ； 适配移动端 ； url 前缀 ； 图片压缩 ； user 的 form 表单校验逻辑 ； 非开发环境无法构建 ； 多环境限制（演示环境无法使用除白名单外的任何非 get 请求）； 前端构建表单宽度少 修复； 打包后个人信息页面无法使用修复 ； 后端构建转驼峰时机调节修复 ； generator 日志需要清除修复 ；, createTime=2025-07-12T10:52:23), Notice(id=11, name=v2026.0.2, content=SpringBoot 版本升级到 3.5+并且处理相关问题 ；\n重构 logback;\n重构 swagger ;\n处理前端 page 组件已经抛弃的方法 ;\nmenu 只展示一个子组件 ;\nhome 组件 数据可视化 bug 修复 ;\n摒弃 vite-plugin-layouts;\ntabbar 栏新增文字提示 ;\n整合Springai 并且调用本地 ollama接口 ;\n整合Springai 远程调用DeepSeek接口 ;\n实现流式返回内容 ;\n通过数据库实现会话记忆 ;\n自定义深度思考 ;\n自定义调用大模型 ;\n清空历史记录 ;\n停止思考 ;\n停止思考时保存消息 ;\n自定义 ai 和用户的头像 ;\nAI 构建 ;\n修改原始驼峰下划线相互长期存在的问题 ;\n废弃前端 settings.js 文件，全部使用多环境配置文件 ;\n优化后台首页布局 ;\n\n\n\n\n\n\n\n\n\n, createTime=2025-06-30T10:58:22), Notice(id=10, name=v2026.0.1, content=角色管理中默认关联问题;\n删除无用 permisiion 数据; \n修改默认配色 ;\n前端公钥加密，后端私钥解密;\n处理 layui 遗留警告;\n处理动画警告 ;\nlayout 移动适配 ;\n普通用户默认权限处理;\nID 更换为序列号 ;\n编辑弹框更换样式;\n用户管理表单组件样式、内容细化（表单弹框换成抽屉组件、对账户名、手机号、邮箱号进行唯一确定）;\n角色管理表单组件样式、内容细化 ;\n菜单管理新增更多规则校验 ;\nMenu 和 Logo 组件修改动画逻辑 ;\n下滑滚动栏的更换 ，替换原来又粗又黑的难看的下滑滚轮 ;\n登录页面样式更换 ;\n注册页面样式更换 ;\n找回密码页面样式更换 ;\n通用样式类提取;\n后台首页样式布局内容修改 ;\n自定义主题色 ;\n在线用户 ;\n切换页面执行动画效果;\n在线用户+WebSocket 实时更新 ;\n新增查询组件 ;\n新增设置系统外观参数组件 ;\n解决打包相关问题 （配置 nginx）;\n多环境配置文件;\n新增网络超时提示 ;\n新增数据字典 ;\n代码生成器优化 1：修改权限位置;\n代码生成器优化 2：新增查询权限;\n代码生成器优化 3：修改布局样式;\n代码生成器优化 4：添加字典关联 ;\n代码生成器优化 5：新增 sql 语句进行构建代码;\n代码生成器优化 6:  create_time和update_time数据回显驼峰化的问题 ;\n代码生成器优化 7：el-dialog 更换为 el-drawer;\n代码生成器优化 8：校验表名是否以“sys_”开头 ;\n代码生成器优化 9：校验构建的表名是否在系统表中（通过字典列表来进行判断）;\n, createTime=2025-06-24T10:44:50), Notice(id=9, name=v3.1.0, content=修复一些已知bug，生成时可加入关联表属性，自定义是否加入查询，优化一些技术样式，修改背景色等等\n, createTime=2024-10-17T19:07:29), Notice(id=8, name=v3.0.9, content=修改一些一致bug，但是不建议使用, createTime=2024-10-17T19:06:43), Notice(id=7, name=v3.0.8, content=（1）修改前端样式；\n（2）实现多图片上传组件\n（3）通过构建记录进行回显构建\n（4）优化后端Bug, createTime=2024-09-26T15:32:47), Notice(id=6, name=v3.0.7, content=修改login页面样式，修改代码生成bug，修改默认密码bug，修改日志bug，修改一些格式问题, createTime=2024-09-02T20:03:17), Notice(id=5, name=v3.0.6, content=新增数据可视化图表, createTime=2023-12-28T14:22:38), Notice(id=4, name=v3.0.5, content=修复一些为止bug，xinz自定义菜单相关配色, createTime=2023-12-26T14:34:44), Notice(id=3, name=v3.0.3, content=修复一些已知bug,和新增一些功能：（1）加入手机号和邮箱的正则校验（2）加入滑块组件、评分组件、计数器组件等！\n, createTime=2023-12-19T09:33:25), Notice(id=2, name=v3.0.1, content=修复一些已知bug, createTime=2023-10-24T20:11:32), Notice(id=1, name=v3.0.0, content=正式发布, createTime=2023-10-24T20:05:32)])', '3', 'Chrome 13', 'Windows 10');
